{"content": "/* ===== CSS Variables ===== */
:root {
  /* Primary Colors */
  --color-purple: hsl(246, 80%, 60%);
  --color-work: hsl(15, 100%, 70%);
  --color-play: hsl(195, 74%, 62%);
  --color-study: hsl(348, 100%, 68%);
  --color-exercise: hsl(145, 58%, 55%);
  --color-social: hsl(264, 64%, 52%);
  --color-self-care: hsl(43, 84%, 65%);

  /* Neutral Colors */
  --color-navy-950: hsl(226, 43%, 10%);
  --color-navy-900: hsl(235, 46%, 20%);
  --color-navy-800: hsl(235, 46%, 25%);
  --color-purple-500: hsl(235, 45%, 61%);
  --color-navy-200: hsl(236, 100%, 87%);
  --color-white: hsl(0, 0%, 100%);

  /* Typography */
  --font-family: 'Rubik', sans-serif;
  --font-size-card-title: 18px;
  --font-weight-300: 300;
  --font-weight-400: 400;
  --font-weight-500: 500;

  /* Spacing */
  --spacing-xs: 8px;
  --spacing-sm: 12px;
  --spacing-md: 16px;
  --spacing-lg: 20px;
  --spacing-xl: 24px;
  --spacing-2xl: 32px;

  /* Border Radius */
  --radius-sm: 8px;
  --radius-md: 12px;
  --radius-lg: 16px;

  /* Card Heights */
  --card-min-height: 200px;
}

/* ===== Reset & Base ===== */
*,
*::before,
*::after {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html {
  font-size: 16px;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

body {
  font-family: var(--font-family);
  font-weight: var(--font-weight-400);
  background-color: var(--color-navy-950);
  color: var(--color-white);
  min-height: 100vh;
  line-height: 1.5;
  padding: var(--spacing-lg);
}

a {
  color: var(--color-purple);
  text-decoration: none;
  transition: color 0.2s ease;
}

a:hover {
  color: var(--color-navy-200);
}

a:focus-visible {
  outline: 2px solid var(--color-purple);
  outline-offset: 2px;
  border-radius: 2px;
}

button {
  font-family: inherit;
  cursor: pointer;
  border: none;
  background: none;
}

/* ===== Dashboard Layout ===== */
.dashboard {
  max-width: 1200px;
  margin: 0 auto;
  display: grid;
  gap: var(--spacing-lg);
}

/* Mobile-first: single column */
.profile-card {
  background-color: var(--color-purple);
  border-radius: var(--radius-lg);
  padding: var(--spacing-xl);
  display: flex;
  flex-direction: column;
  gap: var(--spacing-lg);
}

.profile-info {
  display: flex;
  align-items: center;
  gap: var(--spacing-md);
}

.profile-avatar {
  width: 64px;
  height: 64px;
  border-radius: 50%;
  border: 3px solid var(--color-white);
  object-fit: cover;
}

.profile-text {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.profile-label {
  font-size: 14px;
  font-weight: var(--font-weight-400);
  color: var(--color-navy-200);
  opacity: 0.8;
}

.profile-name {
  font-size: 24px;
  font-weight: var(--font-weight-500);
  line-height: 1.2;
}

.timeframe-nav {
  display: flex;
  gap: var(--spacing-md);
}

.timeframe-btn {
  font-size: 16px;
  font-weight: var(--font-weight-400);
  color: var(--color-purple-500);
  padding: var(--spacing-xs) 0;
  transition: color 0.2s ease;
  position: relative;
}

.timeframe-btn::after {
  content: '';
  position: absolute;
  bottom: -4px;
  left: 0;
  right: 0;
  height: 3px;
  background-color: transparent;
  border-radius: 2px;
  transition: background-color 0.2s ease;
}

.timeframe-btn:hover {
  color: var(--color-white);
}

.timeframe-btn:focus-visible {
  outline: 2px solid var(--color-white);
  outline-offset: 4px;
  border-radius: 2px;
}

.timeframe-btn.active {
  color: var(--color-white);
}

.timeframe-btn.active::after {
  background-color: var(--color-white);
}

/* ===== Activity Cards Grid ===== */
.activity-cards {
  display: grid;
  grid-template-columns: 1fr;
  gap: var(--spacing-lg);
}

/* ===== Activity Card ===== */
.activity-card {
  position: relative;
  background-color: var(--color-navy-900);
  border-radius: var(--radius-md);
  padding: var(--spacing-xl);
  min-height: var(--card-min-height);
  display: flex;
  flex-direction: column;
  justify-content: flex-end;
  overflow: hidden;
  transition: background-color 0.2s ease;
}

.activity-card:hover {
  background-color: var(--color-navy-800);
}

.activity-card:focus-within {
  outline: 2px solid var(--color-purple);
  outline-offset: 2px;
}

/* Card background pattern/icon area */
.card-bg {
  position: absolute;
  top: -10px;
  right: 15px;
  width: 70px;
  height: 70px;
  display: flex;
  align-items: flex-start;
  justify-content: flex-end;
  overflow: hidden;
}

.card-bg svg {
  width: 100%;
  height: 100%;
}

.card-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: var(--spacing-sm);
  position: relative;
  z-index: 1;
}

.card-title {
  font-size: var(--font-size-card-title);
  font-weight: var(--font-weight-500);
}

.card-menu {
  color: var(--color-navy-200);
  padding: 4px;
  border-radius: var(--radius-sm);
  transition: color 0.2s ease;
}

.card-menu:hover {
  color: var(--color-white);
}

.card-menu:focus-visible {
  outline: 2px solid var(--color-white);
  outline-offset: 2px;
}

.card-menu svg {
  display: block;
}

.card-stats {
  position: relative;
  z-index: 1;
}

.card-current-time {
  font-size: 32px;
  font-weight: var(--font-weight-300);
  line-height: 1.1;
  margin-bottom: 4px;
}

.card-previous-time {
  font-size: 14px;
  font-weight: var(--font-weight-400);
  color: var(--color-purple-500);
}

/* ===== Card Color Variants ===== */
.activity-card[data-activity="work"] {
  background-color: var(--color-work);
}

.activity-card[data-activity="play"] {
  background-color: var(--color-play);
}

.activity-card[data-activity="study"] {
  background-color: var(--color-study);
}

.activity-card[data-activity="exercise"] {
  background-color: var(--color-exercise);
}

.activity-card[data-activity="social"] {
  background-color: var(--color-social);
}

.activity-card[data-activity="self-care"] {
  background-color: var(--color-self-care);
}

/* Override card background for colored top */
.activity-card > .card-bg {
  top: 0;
  right: 0;
  width: 100%;
  height: 60px;
  background-color: inherit;
  border-radius: var(--radius-md) var(--radius-md) 0 0;
  align-items: flex-start;
  justify-content: flex-end;
  padding: 10px 15px;
}

.activity-card > .card-bg svg {
  position: relative;
  top: -5px;
  width: 55px;
  height: 55px;
}

/* ===== Responsive - Tablet ===== */
@media (min-width: 600px) {
  body {
    padding: var(--spacing-2xl);
  }

  .dashboard {
    gap: var(--spacing-xl);
  }

  .profile-card {
    flex-direction: row;
    justify-content: space-between;
    align-items: center;
    padding: var(--spacing-2xl);
  }

  .profile-avatar {
    width: 78px;
    height: 78px;
  }

  .profile-name {
    font-size: 28px;
  }

  .activity-cards {
    grid-template-columns: repeat(2, 1fr);
  }

  .card-current-time {
    font-size: 40px;
  }
}

/* ===== Responsive - Desktop ===== */
@media (min-width: 900px) {
  body {
    padding: var(--spacing-2xl) var(--spacing-xl);
    display: flex;
    flex-direction: column;
    justify-content: center;
    min-height: 100vh;
  }

  .dashboard {
    grid-template-columns: 280px 1fr;
    grid-template-rows: auto;
    gap: var(--spacing-xl);
  }

  .profile-card {
    grid-row: 1;
    flex-direction: column;
    align-items: flex-start;
    padding: var(--spacing-2xl);
    height: fit-content;
  }

  .profile-info {
    flex-direction: column;
    align-items: flex-start;
    gap: var(--spacing-md);
  }

  .profile-avatar {
    width: 80px;
    height: 80px;
  }

  .profile-name {
    font-size: 26px;
    line-height: 1.3;
  }

  .timeframe-nav {
    flex-direction: column;
    width: 100%;
    gap: var(--spacing-sm);
  }

  .timeframe-btn {
    padding: var(--spacing-xs) 0;
    text-align: left;
  }

  .timeframe-btn::after {
    display: none;
  }

  .timeframe-btn.active {
    color: var(--color-white);
  }

  .activity-cards {
    grid-column: 2;
    grid-template-columns: repeat(3, 1fr);
    gap: var(--spacing-xl);
  }

  .card-current-time {
    font-size: 36px;
  }

  .attribution {
    text-align: center;
    padding-top: var(--spacing-xl);
  }
}

/* ===== Attribution ===== */
.attribution {
  font-size: 11px;
  color: var(--color-purple-500);
  margin-top: var(--spacing-lg);
}

.attribution a {
  color: var(--color-purple-500);
}

.attribution a:hover {
  color: var(--color-navy-200);
}

/* ===== Reduced Motion ===== */
@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    transition-duration: 0.01ms !important;
    animation-duration: 0.01ms !important;
  }
