(function() {
  'use strict';

  // Activity to icon mapping
  const ACTIVITY_ICONS = {
    'work': `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64" fill="none">
      <path d="M47.2 14.4c0-4.8-3.9-8.8-8.8-8.8H25.6c-4.8 0-8.8 3.9-8.8 8.8v1.6c-3.9 2.3-6.4 6.6-6.4 11.2v9.6c0 7.5 6 13.6 13.6 13.6h12.8c7.5 0 13.6-6 13.6-13.6v-9.6c0-4.6-2.5-8.8-6.4-11.2v-1.6h-1.6v12.8h1.6v-6.4c0-3.2 2.6-5.6 5.6-5.6s5.6 2.6 5.6 5.6v6.4h1.6v-6.4c0-4.8-3.9-8.8-8.8-8.8s-8.8 3.9-8.8 8.8v6.4h3.2V14.4zM16 33.6v-6.4c0-5.6 4.8-10.4 10.4-10.4h12.8c5.6 0 10.4 4.8 10.4 10.4v6.4H16z" fill="currentColor"/>
    </svg>`,
