      <path d="M53.3 16.9c-3.1-1.9-7.1-1.9-10.2 0l-24 14.4C15.6 33.1 13 36.2 13 40v16c0 3.8 2.6 6.9 6.1 7.7l24 14.4c3.1 1.9 7.1 1.9 10.2 0l24-14.4c3.5-.8 6.1-3.9 6.1-7.7V40c0-3.8-2.6-6.9-6.1-7.7l-24-14.4zm2.7 53.1L32 58.6 16 54.1V33.9L32 29.4l16 4.5v20.2z" fill="currentColor"/>
    </svg>`,
