    </svg>`,
    'exercise': `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64" fill="none">
      <path d="M62.4 30.4L54.4 14.4c-1.6-3.2-4.8-5.6-8.8-5.6H40c-4 0-7.2 2.4-8.8 5.6L22.4 30.4c-1.6 3.2-1.6 6.4 0 9.6l8 16c1.6 3.2 4.8 5.6 8.8 5.6h4.8c4 0 7.2-2.4 8.8-5.6l8-16c1.6-3.2 1.6-6.4 0-9.6zM32 45.6c-4.8 0-8-3.2-8-8s3.2-8 8-8 8 3.2 8 8-3.2 8-8 8z" fill="currentColor"/>
