    'social': `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64" fill="none">
      <path d="M44 27.2c-3.2 0-6.4.8-9.6 2.4-3.2-1.6-6.4-2.4-9.6-2.4-12.8 0-22.4 9.6-22.4 22.4S12.8 72 25.6 72c3.2 0 6.4-.8 9.6-2.4 3.2 1.6 6.4 2.4 9.6 2.4 12.8 0 22.4-9.6 22.4-22.4S56.8 27.2 44 27.2zM38.4 68.8c-4 0-7.2-3.2-7.2-7.2S34.4 54.4 38.4 54.4 45.6 57.6 45.6 61.6 42.4 68.8 38.4 68.8zm-22.4-8c-4 0-7.2-3.2-7.2-7.2S12 46.4 16 46.4 23.2 49.6 23.2 53.6 20 60.8 16 60.8zm44-22.4c-4 0-7.2-3.2-7.2-7.2S56 24 60 24s7.2 3.2 7.2 7.2-3.2 7.2-7.2 7.2z" fill="currentColor"/>
    </svg>`,
    'self-care': `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 64 64" fill="none">
      <path d="M54.4 22.4L48 12.8c-1.6-2.4-4-4-6.4-4H38c-2.4 0-4.8 1.6-6.4 4l-6.4 9.6c-1.6 2.4-1.6 4.8 0 7.2l6.4 9.6c1.6 2.4 4 4 6.4 4h3.6c2.4 0 4.8-1.6 6.4-4l6.4-9.6c1.6-2.4 1.6-4.8 0-7.2zM38 36c-3.2 0-6.4-2.4-6.4-6.4S34.8 23.2 38 23.2s6.4 2.4 6.4 6.4S41.2 36 38 36z" fill="currentColor"/>
      <path d="M14.4 28.8c-4 0-6.4 3.2-6.4 6.4v4.8c0 4 3.2 7.2 7.2 7.2h4.8c3.2 0 6.4-2.4 6.4-6.4s-3.2-6.4-6.4-6.4h-1.6V28.8h-4z" fill="currentColor"/>
    </svg>`
  };

  // Previous time labels
  const PREVIOUS_LABELS = {
    daily: 'Yesterday',
    weekly: 'Last Week',
    monthly: 'Last Month'
  };

  // State
  let activityData = [];
  let currentTimeframe = 'weekly';

  // DOM Elements
  const activityCardsContainer = document.getElementById('activity-cards');
  const timeframeButtons = document.querySelectorAll('.timeframe-btn');

  /**
   * Format time display (e.g., "5hrs", "1hr")
   */
  function formatTime(hours) {
    return hours === 1 ? '1hr' : `${hours}hrs`;
  }

  /**
   * Create an activity card element
   */
  function createActivityCard(activity) {
    const card = document.createElement('article');
    card.className = 'activity-card';
    card.dataset.activity = activity.title.toLowerCase().replace(' ', '-');

    const timeframe = activity.timeframes[currentTimeframe];
    const currentTime = formatTime(timeframe.current);
    const previousTime = formatTime(timeframe.previous);
    const previousLabel = PREVIOUS_LABELS[currentTimeframe];

    // Get icon for this activity
    const activityKey = activity.title.toLowerCase().replace(' ', '-');
    const icon = ACTIVITY_ICONS[activityKey] || '';

    card.innerHTML = `
      <div class="card-bg" aria-hidden="true">
        ${icon}
      </div>
      <div class="card-content">
        <div class="card-header">
          <h2 class="card-title">${activity.title}</h2>
          <button class="card-menu" aria-label="More options">
            <svg xmlns="http://www.w3.org/2000/svg" width="21" height="5" viewBox="0 0 21 5" fill="currentColor">
              <circle cx="2.5" cy="2.5" r="2.5"/>
              <circle cx="10.5" cy="2.5" r="2.5"/>
              <circle cx="18.5" cy="2.5" r="2.5"/>
            </svg>
          </button>
        </div>
        <div class="card-stats">
          <p class="card-current-time">${currentTime}</p>
          <p class="card-previous-time">${previousLabel} - ${previousTime}</p>
        </div>
      </div>
    `;

    return card;
  }

  /**
   * Render all activity cards
   */
  function renderActivityCards() {
    activityCardsContainer.innerHTML = '';

    activityData.forEach(activity => {
      const card = createActivityCard(activity);
      activityCardsContainer.appendChild(card);
    });
  }

  /**
   * Update card stats without re-rendering entire cards
   */
  function updateCardStats() {
    const cards = activityCardsContainer.querySelectorAll('.activity-card');

    cards.forEach((card, index) => {
      const activity = activityData[index];
      if (!activity) return;

      const timeframe = activity.timeframes[currentTimeframe];
      const currentTime = formatTime(timeframe.current);
      const previousTime = formatTime(timeframe.previous);
      const previousLabel = PREVIOUS_LABELS[currentTimeframe];

      card.querySelector('.card-current-time').textContent = currentTime;
      card.querySelector('.card-previous-time').textContent = `${previousLabel} - ${previousTime}`;
    });
  }

  /**
   * Handle timeframe button click
   */
  function handleTimeframeClick(event) {
    const button = event.currentTarget;
    const timeframe = button.dataset.timeframe;

    if (timeframe === currentTimeframe) return;

    // Update button states
    timeframeButtons.forEach(btn => {
      const isActive = btn.dataset.timeframe === timeframe;
      btn.classList.toggle('active', isActive);
      btn.setAttribute('aria-pressed', isActive);
    });

    // Update state and re-render
    currentTimeframe = timeframe;
    updateCardStats();
  }

  /**
   * Initialize the dashboard
   */
  async function init() {
    try {
      const response = await fetch('data.json');
      if (!response.ok) {
        throw new Error(`Failed to load data: ${response.status}`);
      }
      activityData = await response.json();

      // Initial render
      renderActivityCards();

      // Attach event listeners to timeframe buttons
      timeframeButtons.forEach(btn => {
        btn.addEventListener('click', handleTimeframeClick);
      });

    } catch (error) {
      console.error('Error initializing dashboard:', error);
      activityCardsContainer.innerHTML = `
        <p class="error-message" style="grid-column: 1 / -1; text-align: center; color: var(--color-purple-500);">
          Unable to load activity data. Please try again later.
        </p>
      `;
    }
  }

  // Start the app when DOM is ready
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }

